import React from "react";
import { Button, Col, Row } from "react-bootstrap";
import firebase from "../controller/firebase";

export const NoteInput = () => {
  const [newTitle, setNewTitle] = React.useState();
  const [newDesc, setNewDesc] = React.useState();
  const [newTimestamp, setNewTimestamp] = React.useState();

  const onCreate = async (e) => {
    e.preventDefault();
    await setNewTimestamp(Date.now());
    const db = firebase.firestore();
    await db.collection("notes/").add({
      title: newTitle,
      description: newDesc,
      timestamp: newTimestamp,
    });
    setNewDesc("");
    setNewTitle("");
    setNewTimestamp("");
  };

  return (
    <form onSubmit={onCreate}>
      <div className="update-card-border">
        <div className="update-card">
          <Row>
            <Col>
              <h1>Add a Note</h1>
            </Col>
          </Row>
          <Row className="underline">
            <Col>
              <h2>Title</h2>
            </Col>
            <Col>
              <input
                className="update-card-input"
                value={newTitle}
                onChange={(e) => setNewTitle(e.target.value)}
                required
              />
            </Col>
          </Row>
          <Row className="underline">
            <h2>Description</h2>
            <textarea
              className="update-card-input text-area"
              rows={5}
              cols={5}
              value={newDesc}
              onChange={(e) => setNewDesc(e.target.value)}
              required
            />
          </Row>

          <Button
            className="update-card-button"
            type="submit"
            variant="danger"
            size="lg"
            block
          >
            Add Note
          </Button>
        </div>
      </div>
    </form>
  );
};
