import React from "react";
import firebase from "../../controller/firebase";
import { Button, Col, Row } from "react-bootstrap";
import { useHistory } from "react-router";

function NewCharacterForm() {
  const [newName, setNewName] = React.useState();
  const [newRace, setNewRace] = React.useState();
  const [newClass, setNewClass] = React.useState();
  const [newPicture, setNewPicture] = React.useState();
  const [newBackgroundPicture, setNewBackgroundPicture] = React.useState();
  const [newHitPoints, setNewHitPoints] = React.useState();
  const [newArmorClass, setNewArmorClass] = React.useState();
  const [newSpeed, setNewSpeed] = React.useState();
  const [newHitDice, setNewHitDice] = React.useState();
  const [newStrength, setNewStrength] = React.useState();
  const [newDexterity, setNewDexterity] = React.useState();
  const [newConstitution, setNewConstitution] = React.useState();
  const [newIntelligence, setNewIntelligence] = React.useState();
  const [newWisdom, setNewWisdom] = React.useState();
  const [newCharisma, setNewCharisma] = React.useState();
  const [newBackground, setNewBackground] = React.useState();
  const [newPersonalityTraits, setNewPersonalityTraits] = React.useState();
  const [newIdeals, setNewIdeals] = React.useState();
  const [newBonds, setNewBonds] = React.useState();
  const [newFlaws, setNewFlaws] = React.useState();
  const [newLevel, setNewLevel] = React.useState();
  const [newSkills, setNewSkills] = React.useState([]); //not needed!
  const [newSavingThrows, setNewSavingThrows] = React.useState();
  const [newProficiencies, setNewProficiencies] = React.useState([]);

  const history = useHistory();
  const onCreate = async (e) => {
    e.preventDefault();
    var skillsArr = [];
    const checkedBoxes = document.querySelectorAll(
      "input[type=checkbox]:checked"
    );
    console.log(checkedBoxes);
    await checkedBoxes.forEach((box) => skillsArr.push(box.value));
    console.log(skillsArr);

    const db = firebase.firestore();
    await db.collection("characters").add({
      name: newName,
      race: newRace,
      class: newClass,
      pictureURL: newPicture,
      backgroundPicture: newBackgroundPicture,
      hitPoints: newHitPoints,
      armorClass: newArmorClass,
      speed: newSpeed,
      hitDice: newHitDice,
      strength: newStrength,
      dexterity: newDexterity,
      constitution: newConstitution,
      intelligence: newIntelligence,
      wisdom: newWisdom,
      charisma: newCharisma,
      background: newBackground,
      personalityTraits: newPersonalityTraits,
      ideals: newIdeals,
      bonds: newBonds,
      flaws: newFlaws,
      level: newLevel,
      skills: skillsArr,
      savingThrows: newSavingThrows,
      proficiencies: newProficiencies,
    });
    let path = "/Characters";

    history.push(path);
  };

  return (
    <form onSubmit={onCreate}>
      <div className="update-card-border">
        <div className="update-card">
          <Row className="underline">
            <Col>
              <h2>Name</h2>
            </Col>
            <Col>
              <input
                className="update-card-input"
                value={newName}
                onChange={(e) => setNewName(e.target.value)}
                required
              />
            </Col>
          </Row>
          <Row className="underline">
            <Col>
              <h2>Class</h2>
            </Col>
            <Col>
              <input
                className="update-card-input"
                value={newClass}
                onChange={(e) => setNewClass(e.target.value)}
                required
              />
            </Col>
          </Row>
          <Row className="underline">
            <Col>
              <h2>Race</h2>
            </Col>
            <Col>
              <input
                className="update-card-input"
                value={newRace}
                onChange={(e) => setNewRace(e.target.value)}
                required
              />
            </Col>
          </Row>
          <Row className="underline">
            <Col>
              <h2>Picture (URL)</h2>
            </Col>
            <Col>
              <input
                className="update-card-input"
                value={newPicture}
                onChange={(e) => setNewPicture(e.target.value)}
                required
              />
            </Col>
          </Row>
          <Row className="underline">
            <Col>
              <h2>Background Picture (URL)</h2>
            </Col>
            <Col>
              <input
                className="update-card-input"
                value={newBackgroundPicture}
                onChange={(e) => setNewBackgroundPicture(e.target.value)}
              />
            </Col>
          </Row>
          <Row className="underline">
            <Col sm={4}>
              <h2>Strength</h2>
            </Col>
            <Col>
              <input
                className="update-card-input"
                value={newStrength}
                onChange={(e) => setNewStrength(e.target.value)}
                required
              />
            </Col>
            <Col sm={4}>
              <h2>Dexterity</h2>
            </Col>
            <Col>
              <input
                className="update-card-input"
                value={newDexterity}
                onChange={(e) => setNewDexterity(e.target.value)}
                required
              />
            </Col>
          </Row>
          <Row className="underline">
            <Col sm={4}>
              <h2>Constitution</h2>
            </Col>
            <Col>
              <input
                className="update-card-input"
                value={newConstitution}
                onChange={(e) => setNewConstitution(e.target.value)}
                required
              />
            </Col>
            <Col sm={4}>
              <h2>Intelligence</h2>
            </Col>
            <Col>
              <input
                className="update-card-input"
                value={newIntelligence}
                onChange={(e) => setNewIntelligence(e.target.value)}
                required
              />
            </Col>
          </Row>
          <Row className="underline">
            <Col sm={4}>
              <h2>Wisdom</h2>
            </Col>
            <Col>
              <input
                className="update-card-input"
                value={newWisdom}
                onChange={(e) => setNewWisdom(e.target.value)}
                required
              />
            </Col>
            <Col sm={4}>
              <h2>Charisma</h2>
            </Col>
            <Col>
              <input
                className="update-card-input"
                value={newCharisma}
                onChange={(e) => setNewCharisma(e.target.value)}
                required
              />
            </Col>
          </Row>
          <Row className="underline">
            <Col>
              <h2>Background</h2>
            </Col>
            <Col>
              <input
                className="update-card-input"
                value={newBackground}
                onChange={(e) => setNewBackground(e.target.value)}
                required
              />
            </Col>
          </Row>
          <Row className="underline">
            <Col>
              <h2>Personality Traits</h2>
            </Col>
            <Col>
              <input
                className="update-card-input"
                value={newPersonalityTraits}
                onChange={(e) => setNewPersonalityTraits(e.target.value)}
                required
              />
            </Col>
          </Row>
          <Row className="underline">
            <Col>
              <h2>Ideals</h2>
            </Col>
            <Col>
              <input
                className="update-card-input"
                value={newIdeals}
                onChange={(e) => setNewIdeals(e.target.value)}
                required
              />
            </Col>
          </Row>
          <Row className="underline">
            <Col>
              <h2>Bonds</h2>
            </Col>
            <Col>
              <input
                className="update-card-input"
                value={newBonds}
                onChange={(e) => setNewBonds(e.target.value)}
                required
              />
            </Col>
          </Row>
          <Row className="underline">
            <Col>
              <h2>Flaws</h2>
            </Col>
            <Col>
              <input
                className="update-card-input"
                value={newFlaws}
                onChange={(e) => setNewFlaws(e.target.value)}
                required
              />
            </Col>
          </Row>
          <Row className="underline">
            <Col>
              <h2>Hit Points</h2>
            </Col>
            <Col>
              <input
                className="update-card-input"
                value={newHitPoints}
                onChange={(e) => setNewHitPoints(e.target.value)}
                required
              />
            </Col>
            <Col>
              <h2>Armor Class</h2>
            </Col>
            <Col>
              <input
                className="update-card-input"
                value={newArmorClass}
                onChange={(e) => setNewArmorClass(e.target.value)}
                required
              />
            </Col>
          </Row>
          <Row className="underline">
            <Col>
              <h2>Speed</h2>
            </Col>
            <Col>
              <input
                className="update-card-input"
                value={newSpeed}
                onChange={(e) => setNewSpeed(e.target.value)}
                required
              />
            </Col>
            <Col>
              <h2>Hit Dice</h2>
            </Col>
            <Col>
              <input
                className="update-card-input"
                value={newHitDice}
                onChange={(e) => setNewHitDice(e.target.value)}
                required
              />
            </Col>
          </Row>
          <Row className="underline">
            <Col>
              <h2>Level</h2>
            </Col>
            <Col>
              <input
                className="update-card-input"
                value={newLevel}
                onChange={(e) => setNewLevel(e.target.value)}
                required
              />
            </Col>
          </Row>

          <Row className="underline">
            <Col>
              <h2>Proficiencies</h2>
            </Col>
            <Col>
              <input
                className="update-card-input"
                value={newProficiencies}
                onChange={(e) => setNewProficiencies(e.target.value)}
                required
              />
            </Col>
          </Row>
          <Row className="underline">
            <Col>
              <h2>Saving Throws</h2>
            </Col>
            <Col>
              <input
                className="update-card-input"
                value={newSavingThrows}
                onChange={(e) => setNewSavingThrows(e.target.value)}
                required
              />
            </Col>
          </Row>
          <div className="skills">
            <h2>Skills</h2>
            <Row>
              <Col>
                <label>
                  <input
                    type="checkbox"
                    name={"acrobatics"}
                    value="acrobatics"
                    id="acrobatics"
                  />
                  Acrobatics
                </label>
              </Col>
              <Col>
                <label>
                  <input
                    type="checkbox"
                    name={"animalHandling"}
                    value="animalHandling"
                    id="animalHandling"
                  />
                  Animal Handling
                </label>
              </Col>
              <Col>
                <label>
                  <input
                    type="checkbox"
                    name={"arcana"}
                    value="arcana"
                    id="arcana"
                  />
                  Arcana
                </label>
              </Col>
              <Col>
                <label>
                  <input
                    type="checkbox"
                    name={"athletics"}
                    value="athletics"
                    id="athletics"
                  />
                  Athletics
                </label>
              </Col>
              <Col>
                <label>
                  <input
                    type="checkbox"
                    name={"deception"}
                    value="deception"
                    id="deception"
                  />
                  Deception
                </label>
              </Col>
              <Col>
                <label>
                  <input
                    type="checkbox"
                    name={"history"}
                    value="history"
                    id="history"
                  />
                  History
                </label>
              </Col>
            </Row>
            <Row>
              <Col>
                <label>
                  <input
                    type="checkbox"
                    name={"insight"}
                    value="insight"
                    id="insight"
                  />
                  Insight
                </label>
              </Col>
              <Col>
                <label>
                  <input
                    type="checkbox"
                    name={"intimidation"}
                    value="intimidation"
                    id="intimidation"
                  />
                  Intimidation
                </label>
              </Col>
              <Col>
                <label>
                  <input
                    type="checkbox"
                    name={"investigation"}
                    value="investigation"
                    id="investigation"
                  />
                  Investigation
                </label>
              </Col>
              <Col>
                <label>
                  <input
                    type="checkbox"
                    name={"medicine"}
                    value="medicine"
                    id="medicine"
                  />
                  Medicine
                </label>
              </Col>
              <Col>
                <label>
                  <input
                    type="checkbox"
                    name={"nature"}
                    value="nature"
                    id="nature"
                  />
                  Nature
                </label>
              </Col>
              <Col>
                <label>
                  <input
                    type="checkbox"
                    name={"perception"}
                    value="perception"
                    id="perception"
                  />
                  Perception
                </label>
              </Col>
            </Row>
            <Row>
              <Col>
                <label>
                  <input
                    type="checkbox"
                    name={"performance"}
                    value="performance"
                    id="performance"
                  />
                  Performance
                </label>
              </Col>
              <Col>
                <label>
                  <input
                    type="checkbox"
                    name={"persuasion"}
                    value="persuasion"
                    id="persuasion"
                  />
                  Persuasion
                </label>
              </Col>
              <Col>
                <label>
                  <input
                    type="checkbox"
                    name={"religion"}
                    value="religion"
                    id="religion"
                  />
                  Religion
                </label>
              </Col>
              <Col>
                <label>
                  <input
                    type="checkbox"
                    name={"sleightOfHand"}
                    value="sleightOfHand"
                    id="sleightOfHand"
                  />
                  Sleight of Hand
                </label>
              </Col>
              <Col>
                <label>
                  <input
                    type="checkbox"
                    name={"stealth"}
                    value="stealth"
                    id="stealth"
                  />
                  Stealth
                </label>
              </Col>
              <Col>
                <label>
                  <input
                    type="checkbox"
                    name={"survival"}
                    value="survival"
                    id="survival"
                  />
                  Survival
                </label>
              </Col>
            </Row>
          </div>
          <Button
            classname="update-card-button"
            type="submit"
            variant="danger"
            size="lg"
            block
          >
            Create
          </Button>
        </div>
      </div>
    </form>
  );
}

export default NewCharacterForm;
