import React, { useCallback } from "react";
import { Button, Col, Container, Row, Tabs, Tab, Table } from "react-bootstrap";
import firebase from "./firebase";
import SingleCharacterAbilitiesView from "./singleCharacterAbilitiesView";
import SingleCharacterSpellsView from "./singleCharacterSpellsView";

const GetSingleCharacterService = ({ docId }) => {
  const [character, setCharacter] = React.useState("");
  const [key, setKey] = React.useState("basicInfo");
  const allSkills = [
    "Acrobatics",
    "Animal Handling",
    "Arcana",
    "Athletics",
    "Deception",
    "History",
    "Insight",
    "Intimidation",
    "Investigation",
    "Medicine",
    "Nature",
    "Perception",
    "Performance",
    "Persuasion",
    "Religion",
    "Sleight Of Hand",
    "Stealth",
    "Survival",
  ];

  const fetchCharacter = useCallback(async () => {
    await firebase
      .firestore()
      .collection("characters")
      .doc(docId)
      .get()
      .then((snapshot) => {
        console.log(snapshot.data());
        //character = { ...snapshot.data() };
        setCharacter(snapshot.data());
      })
      .catch((e) => console.log(e));
  });

  React.useEffect(() => {
    if (character !== "") {
      return;
    }
    fetchCharacter();
  }, [fetchCharacter]);

  function getSkillAttribute(skill) {
    if (skill === "Athletics") {
      return "STR";
    } else if (
      skill === "Acrobatics" ||
      skill === "Sleight Of Hand" ||
      skill === "Stealth"
    ) {
      return "DEX";
    } else if (
      skill === "Arcana" ||
      skill === "History" ||
      skill === "Investigation" ||
      skill === "Nature" ||
      skill === "Religion"
    ) {
      return "INT";
    } else if (
      skill === "Animal Handling" ||
      skill === "Insight" ||
      skill === "Medicine" ||
      skill === "Perception" ||
      skill === "Survival"
    ) {
      return "WIS";
    } else if (
      skill === "Deception" ||
      skill === "Intimidation" ||
      skill === "Performance" ||
      skill === "Persuasion"
    ) {
      return "CHA";
    } else {
      return "UKN";
    }
  }

  function isProficientInSkill(skill) {
    if (character === "") {
      return;
    }
    var tempSkill = skill.toLowerCase();
    if (tempSkill === "animal handling") {
      tempSkill = "animalHandling";
    }
    if (tempSkill === "sleight of hand") {
      tempSkill = "sleightOfHand";
    }

    if (character.skills.includes(tempSkill)) {
      return true;
    } else {
      return false;
    }
  }

  function getProficiencyBonus(level) {
    if (character === "") {
      return;
    }
    if (level > 0 && level < 5) {
      return 2;
    } else if (level > 4 && level < 9) {
      return 3;
    } else if (level > 8 && level < 13) {
      return 4;
    } else if (level > 12 && level < 17) {
      return 5;
    } else if (level > 16 && level < 21) {
      return 6;
    } else return 9999;
  }

  function getAbilityMod(score) {
    var mod = (score - 10) / 2;
    return mod;
  }

  function getTotalModWithProficiency(character, level, modType) {
    var score = 0;
    if (modType === "STR") {
      score = character.strength;
    } else if (modType === "DEX") {
      score = character.dexterity;
    } else if (modType === "CON") {
      score = character.constitution;
    } else if (modType === "WIS") {
      score = character.wisdom;
    } else if (modType === "INT") {
      score = character.intelligence;
    } else if (modType === "CHA") {
      score = character.charisma;
    }

    var totalMod = getAbilityMod(score);
    totalMod += getProficiencyBonus(level);

    if (totalMod >= 0) {
      return "+" + Math.floor(totalMod);
    } else {
      return Math.floor(totalMod);
    }
  }
  function getTotalModWithoutProficiency(character, level, modType) {
    var score = 0;
    if (modType === "STR") {
      score = character.strength;
    } else if (modType === "DEX") {
      score = character.dexterity;
    } else if (modType === "CON") {
      score = character.constitution;
    } else if (modType === "WIS") {
      score = character.wisdom;
    } else if (modType === "INT") {
      score = character.intelligence;
    } else if (modType === "CHA") {
      score = character.charisma;
    }
    var totalMod = getAbilityMod(score);

    if (totalMod >= 0) {
      return "+" + Math.floor(totalMod);
    } else {
      return Math.floor(totalMod);
    }
  }

  return (
    <div className="single-character">
      <Tabs
        id="controlled-tab-example"
        activeKey={key}
        onSelect={(k) => setKey(k)}
      >
        <Tab eventKey="basicInfo" title="Basic Info" tabClassName="tab-name">
          <div className="single-character-container-name">
            <Row className="underline">
              <Col>
                <h1 className="view-character ">{character.name}</h1>
              </Col>
            </Row>
          </div>
          <img
            className="character-portrait"
            src={character.pictureURL}
            alt="pic"
          />

          <Container className="single-character-container">
            <Row>
              <Col>
                <h2>Basic Info</h2>
              </Col>
            </Row>
            <Row className="underline">
              <Col>
                <h3>Class: {character.class}</h3>
              </Col>
              <Col>
                <h3>Race: {character.race}</h3>
              </Col>
              <Col>
                <h3>Level: {character.level}</h3>
              </Col>
            </Row>
            <Row className="underline">
              <Col>
                <h3>Background: {character.background}</h3>
              </Col>
            </Row>
            <Row className="underline">
              <Col>
                <h3>Flaws: {character.flaws}</h3>
              </Col>
            </Row>
            <Row className="underline">
              <Col>
                <h3>Ideals: {character.ideals}</h3>
              </Col>
            </Row>
            <Row className="underline">
              <Col>
                <h3>Bonds: {character.bonds}</h3>
              </Col>
            </Row>
            <Row>
              <Col>
                <h3>Personality Traits: {character.personalityTraits}</h3>
              </Col>
            </Row>
          </Container>
          <Container className="single-character-container">
            <Row>
              <Col>
                <h2>Ability Attributes</h2>
              </Col>
            </Row>
            <Row className="underline">
              <Col>
                <h3>
                  Strength: {character.strength} (
                  {getAbilityMod(character.strength) >= 0
                    ? "+" + getAbilityMod(character.strength)
                    : getAbilityMod(character.strength)}
                  )
                </h3>
              </Col>
              <Col>
                <h3>
                  Dexterity: {character.dexterity} (
                  {getAbilityMod(character.dexterity) >= 0
                    ? "+" + getAbilityMod(character.dexterity)
                    : getAbilityMod(character.dexterity)}
                  )
                </h3>
              </Col>
              <Col>
                <h3>
                  Constitution: {character.constitution}(
                  {getAbilityMod(character.constitution) >= 0
                    ? "+" + getAbilityMod(character.constitution)
                    : getAbilityMod(character.constitution)}
                  ){" "}
                </h3>
              </Col>
            </Row>
            <Row className="underline">
              <Col>
                <h3>
                  Wisdom: {character.wisdom} (
                  {getAbilityMod(character.wisdom) >= 0
                    ? "+" + getAbilityMod(character.wisdom)
                    : getAbilityMod(character.wisdom)}
                  )
                </h3>
              </Col>
              <Col>
                <h3>
                  Intelligence: {character.intelligence}(
                  {getAbilityMod(character.intelligence) >= 0
                    ? "+" + getAbilityMod(character.intelligence)
                    : getAbilityMod(character.intelligence)}
                  ){" "}
                </h3>
              </Col>
              <Col>
                <h3>
                  Charisma: {character.charisma} (
                  {getAbilityMod(character.charisma) >= 0
                    ? "+" + getAbilityMod(character.charisma)
                    : getAbilityMod(character.charisma)}
                  )
                </h3>
              </Col>
            </Row>
            <Row className="underline">
              <Col>
                <h3>Speed: {character.speed}</h3>
              </Col>
              <Col>
                <h3>Armor Class: {character.armorClass}</h3>
              </Col>
              <Col>
                <h3>Hit-Points: {character.hitPoints}</h3>
              </Col>
            </Row>
            <Row className="underline">
              <Col>
                <h3>Hit-Dice: {character.hitDice}</h3>
              </Col>
              <Col>
                <h3>
                  Proficiency Bonus: {getProficiencyBonus(character.level)}
                </h3>
              </Col>
              <Col>
                <h3>Inspiration: TBD</h3>
              </Col>
            </Row>
            <Row>
              <Col>
                <h3>Saving Throws: {character.savingThrows}</h3>
              </Col>
              <Col>
                <h3>Proficiencies: {character.proficiencies}</h3>
              </Col>
            </Row>
          </Container>
        </Tab>
        <Tab eventKey="skillsView" title="Skills" tabClassName="tab-name">
          <div className="single-character-container-name">
            <Row className="underline">
              <Col>
                <Table
                  striped
                  bordered
                  hover
                  variant="dark"
                  responsive="sm"
                  size="sm"
                >
                  <thead>
                    <tr>
                      <th>Skill</th>
                      <th>Added Value</th>
                    </tr>
                  </thead>
                  <tbody>
                    {allSkills.map((skill) => (
                      <tr>
                        <td
                          className={
                            isProficientInSkill(skill) ? "proficient-skill" : ""
                          }
                        >
                          {skill} ({getSkillAttribute(skill)})
                        </td>
                        <td>
                          {isProficientInSkill(skill)
                            ? getTotalModWithProficiency(
                                character,
                                character.level,
                                getSkillAttribute(skill)
                              )
                            : getTotalModWithoutProficiency(
                                character,
                                character.level,
                                getSkillAttribute(skill)
                              )}
                        </td>
                      </tr>
                    ))}
                  </tbody>
                </Table>
              </Col>
            </Row>
          </div>
        </Tab>
        <Tab eventKey="abilitiesView" title="Abilities" tabClassName="tab-name">
          <SingleCharacterAbilitiesView docId={docId} />
        </Tab>
        <Tab eventKey="spellsView" title="Spells" tabClassName="tab-name">
          <SingleCharacterSpellsView docId={docId} />
        </Tab>
      </Tabs>
      <Button
        className="sing-character-update-button"
        variant="dark"
        block
        size="lg"
        href={"/BarrysNotesOnBarovia/#/CharacterUpdate/" + docId}
      >
        Update
      </Button>
    </div>
  );
};

export default GetSingleCharacterService;
