import React from "react";
import { Button, Col, Container, Row } from "react-bootstrap";
import firebase from "./firebase";

function GetNotesService() {
  const [notes, setNotes] = React.useState([]);

  React.useEffect(() => {
    const fetchData = async () => {
      const db = firebase.firestore();
      const data = await db.collection("notes").get();
      setNotes(data.docs.map((doc) => ({ id: doc.id, ...doc.data() })));
    };
    fetchData();
  }, []);

  return (
    <>
      <Row>
        {notes.map((note) => (
          <div className="update-card-border">
            <div className="update-card">
              <Row>
                <Col>
                  <h1>{note.title}</h1>
                </Col>
              </Row>
              <Row>
                <Col>{note.description}</Col>
              </Row>
              <Row>{note.timestamp}</Row>
            </div>
          </div>
        ))}
      </Row>
    </>
  );
}

export default GetNotesService;
